async def add_football_on_surface():
    objs = await get_all_objects()
    surface = next((o for o in objs['landmarks'] if 'stack_base' in o['name']), None)
    if surface:
        return await add_object('football', surface['position'][0], surface['position'][1], surface['position'][2] + 0.06, shape='sphere', color='white', size=0.04)
    return {'success': False, 'message': 'Surface not found'}
